#import <Foundation/Foundation.h>

static NSString *ImageDirectory(void) {
    NSArray *paths = NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES);
    if(paths.count == 0)
        return nil;

    return [[paths objectAtIndex:0] stringByAppendingPathComponent:@"んまmod"];
}

