static void WriteImageIfMissing(NSFileManager *fileManager, NSString *directory, NSString *fileName, NSString *base64) {
    NSString *path = [directory stringByAppendingPathComponent:fileName];
    if([fileManager fileExistsAtPath:path])
        return;

    NSData *imageData = [[NSData alloc] initWithBase64EncodedString:base64 options:0];
    if(imageData.length == 0)
        return;

    [imageData writeToFile:path atomically:YES];
}

static void WriteImageAlways(NSFileManager *fileManager, NSString *directory, NSString *fileName, NSString *base64) {
    NSString *path = [directory stringByAppendingPathComponent:fileName];
    NSData *imageData = [[NSData alloc] initWithBase64EncodedString:base64 options:0];
    if(imageData.length == 0)
        return;

    [imageData writeToFile:path atomically:YES];
}

__attribute__((constructor))
void InstallImages(void) {
    @autoreleasepool {
        NSString *imageDirectory = ImageDirectory();
        if(imageDirectory.length == 0)
            return;

        NSFileManager *fileManager = [NSFileManager defaultManager];
        BOOL isDirectory = NO;
        if(![fileManager fileExistsAtPath:imageDirectory isDirectory:&isDirectory]) {
            if(![fileManager createDirectoryAtPath:imageDirectory withIntermediateDirectories:YES attributes:nil error:nil])
                return;
        } else if(!isDirectory) {
            return;
        }

        WriteImageIfMissing(fileManager, imageDirectory, @"back.png", kBackImageBase64);
        WriteImageIfMissing(fileManager, imageDirectory, @"close.png", kCloseImageBase64);
        WriteImageIfMissing(fileManager, imageDirectory, @"in.png", kInImageBase64);
        WriteImageAlways(fileManager, imageDirectory, @"menuIcon.png", kMenuIconImageBase64);
        WriteImageAlways(fileManager, imageDirectory, @"masterSplitButton.png", kMasterSplitButtonImageBase64);
        WriteImageIfMissing(fileManager, imageDirectory, @"sliderIcon.png", kSliderIconImageBase64);
    }
}
